        "detour": "proxy"
      },
      {
        "tag": "local",
        "address": "tls://223.5.5.5",
        "detour": "direct"
      },
      {
        "tag": "block",
        "address": "rcode://success"
      }
    ],
    "rules": [
      {
        "server": "local_local",
        "domain": [
          "VPS域名"
        ]
      },
      {
        "server": "block",
        "rule_set": [
          "geosite-category-ads-all"
        ]
      },
      {
        "server": "remote",
        "rule_set": [
          "geosite-geolocation-!cn"
        ]
      },
      {
        "server": "local",
        "rule_set": [
          "geosite-cn",
          "geosite-geolocation-cn"
        ]
      }
    ],
    "final": "remote",
    "strategy": "ipv4_only"
  },
第一个”local_local“server是系统生成的，可以看见它没有跟下面”local“的server保持一致。我只有通过全局设置保持所有的server解析都是ipv4_only。

